<template><section class="page"><div class="panel"><el-table :data="rows" v-loading="loading"><el-table-column prop="batch_no" label="批次号"/><el-table-column prop="trigger_type" label="触发方式"/><el-table-column prop="status" label="状态"/><el-table-column prop="total_count" label="总数"/><el-table-column prop="success_count" label="成功"/><el-table-column prop="difference_count" label="差异"/><el-table-column prop="inserted_event_count" label="补入事件"/></el-table></div></section></template><script setup lang="ts">import { onMounted, onUnmounted, ref } from 'vue'; import { http } from '../api/http'; const rows=ref<any[]>([]); const loading=ref(false); let timer:number|undefined; async function load(){loading.value=true; try{rows.value=await http.get('/reconciliation/batches')} finally{loading.value=false}} onMounted(()=>{load(); timer=window.setInterval(load,5000)}); onUnmounted(()=>timer&&clearInterval(timer))</script>
